var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"자, 이렇게 밀가루옷을 입혀서 기름에 넣으면......","JPN":"ほら、こうして衣を付けて油に入れると……","ENG":"Now, you coat the chicken in flour and stick it in oil like this...","TWN":"來，沾點麵粉後放入油鍋的話 ……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"어때? 배달로 시켜 먹던 거랑 똑같지?","JPN":"どう？　出前のものと味は変わらないでしょ？","ENG":"Well? Isn't it just like the fried chicken you got delivered?","TWN":"如何？跟你們點外送吃的炸雞口味一模一樣吧？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SORIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"오오오, 정말로 치킨 맛이 난다!","JPN":"おおお、本当にフライドチキンの味がする！","ENG":"Ooh! It really is!","TWN":"噢噢噢。真的是炸雞的味道！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SORIM_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"그야 같은 재료를 썼으니 당연하지.","JPN":"そりゃあ同じ材料を使ったから当たり前だよ。","ENG":"Of course. We used the same ingredients.","TWN":"那是因為用同樣的食材啊。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_NPC_NULL_NULL","text":{"KOREA":"이걸로 다시 제게도 몸을 돌려주실 이유가 생겼네요, 주인님.","JPN":"これで私に身体を戻してくださる理由ができましたね、我が主。","ENG":"Now you finally have a reason to give me my body back, Mistress.","TWN":"現在有了還我身軀的理由了，主人。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"내가 왜 그래야 하지?","JPN":"妾が？　何故？","ENG":"Why should I?","TWN":"我為什麼要這樣做呢？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOMA_NPC_NULL_NULL","text":{"KOREA":"게으르신 주인님은 레시피가 있어도 직접 요리를 하지 않으실 테니까요.","JPN":"怠け者の我が主はレシピがあってもご自身で料理をすることはないはずでしょう。","ENG":"Because you're too lazy to cook even if you've got the recipe.","TWN":"因為主人太懶惰了，即使有了食譜也不會親自做料理。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"......흥, 건방지구나. 네가 없어도 요리 정도는 만들 수 있다.","JPN":"……ふん、生意気な口をきくな。其方がいなくても料理程度はできるのじゃ。","ENG":"...Hmpf, insolent fool. I can cook just fine without you.","TWN":" ……哼，太放肆了，即使沒有你，我也可以做料理呢。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"프리랜서! 어서 날 위해 파전을 구워 보도록!","JPN":"そこのフリーランス、さっそく妾のためにお好み焼きを作りたまえ。","ENG":"Freelancer! Make me some seafood pancakes!","TWN":"自由工作者！快點為我做點蔥餅！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOO_SHI_YEONG_NPC_FOOLSDAY_NULL","text":{"KOREA":"죄송하지만 저도 이젠 집에 돌아가야 할 시간이에요.","JPN":"申し訳ございませんが、私もそろそろ帰る時間ですよ。","ENG":"Sorry, but I have to get home now.","TWN":"很抱歉，我差不多要回家了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JOO_SHI_YEONG_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOO_SHI_YEONG_NPC_FOOLSDAY_NULL","text":{"KOREA":"카린 양이 잔뜩 화가 나서 기다리고 있을 테니까요.","JPN":"カリンさんが今頃かなり怒っているはずなので戻らないとまずいです。","ENG":"Karin must be very upset, waiting for me.","TWN":"卡琳小姐一定很生氣在等著我回去的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JOO_SHI_YEONG_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"끄응...... 어쩔 수 없군. 시종!","JPN":"むう……仕方ない。僕よ！","ENG":"Ugh... You leave me no choice. Servant!","TWN":"呃嗯 …… 沒辦法了，侍從！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"호오, 이거 놀라운데요?","JPN":"ほお、これは驚きですね。","ENG":"Oh, this is amazing!","TWN":"噢噢，太厲害了？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"닭, 밀가루, 올리브유 그리고 조리기구만을 이용해서 이렇게 간단히 치킨을 만들 수 있다니.","JPN":"鶏肉、小麦粉、油そして調理道具だけでこんな簡単にフライドチキンを作ることができるなんて。","ENG":"Who knew a simple combination of chicken, flour, and oil could produce such a wondrous dish?","TWN":"雞、麵粉、橄欖油，還有幾個調理工具就可以簡單作炸雞。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"어째서 아무도 지금까지 이런 생각을 하지 못했던 걸까요?","JPN":"どうして今まで誰もこの発想ができなかったのでしょう？","ENG":"How come no one's thought of this before?","TWN":"怎麼直到現在都沒有人想到這個方法呢？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_NPC_FOOLSDAY_NULL","text":{"KOREA":"치킨에도 위아래가 있는 법이다, 주시윤.","JPN":"フライドチキンにも年功序列があるぞ、アキヤマ。","ENG":"Respect your elders, Shiyoon.","TWN":"吃炸雞也要敬老尊賢長幼有序啊，周時雲。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"HILDE_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_NPC_FOOLSDAY_NULL","text":{"KOREA":"은근슬쩍 다리 가져가지 마.","JPN":"先に大きいのを取るのはやめろ。","ENG":"I got dibs on the drumsticks.","TWN":"不要偷偷摸摸拿走雞腿啊。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"HILDE_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};